import { useState, useEffect } from 'react';
import { getAvailability, updateAvailability } from '../utils/api';
import toast from 'react-hot-toast';
import './Availability.css';

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

const TIMEZONES = [
  'America/New_York', 'America/Chicago', 'America/Denver', 'America/Los_Angeles',
  'Europe/London', 'Europe/Paris',
  'Asia/Tokyo', 'Asia/Kolkata',
  'Australia/Sydney'
];

const TIME_OPTIONS = [];
for (let h = 0; h < 24; h++) {
  for (let m = 0; m < 60; m += 30) {
    const hStr = h.toString().padStart(2, '0');
    const mStr = m.toString().padStart(2, '0');
    const val = `${hStr}:${mStr}`;
    const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
    const ampm = h < 12 ? 'AM' : 'PM';
    TIME_OPTIONS.push({ value: val, label: `${hour12}:${mStr} ${ampm}` });
  }
}

export default function Availability() {
  const [schedule, setSchedule] = useState(null);
  const [slots, setSlots] = useState({});
  const [timezone, setTimezone] = useState('Asia/Kolkata');
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSchedule();
  }, []);

  async function fetchSchedule() {
    try {
      const { data } = await getAvailability();
      setSchedule(data);
      setTimezone(data.timezone);

      const slotsMap = {};
      for (let d = 0; d < 7; d++) {
        const slot = data.slots.find(s => s.day_of_week === d);
        slotsMap[d] = slot
          ? { enabled: slot.is_active, start: slot.start_time, end: slot.end_time }
          : { enabled: false, start: '09:00', end: '17:00' };
      }
      setSlots(slotsMap);
    } finally {
      setLoading(false);
    }
  }

  function toggleDay(day) {
    setSlots(s => ({
      ...s,
      [day]: { ...s[day], enabled: !s[day].enabled }
    }));
  }

  function updateSlot(day, field, value) {
    setSlots(s => ({
      ...s,
      [day]: { ...s[day], [field]: value }
    }));
  }

  async function handleSave() {
    setSaving(true);
    try {
      const slotsData = Object.entries(slots)
        .filter(([, s]) => s.enabled)
        .map(([day, s]) => ({
          day_of_week: parseInt(day),
          start_time: s.start,
          end_time: s.end,
          is_active: true,
        }));

      await updateAvailability({ timezone, slots: slotsData });
      toast.success('Availability saved!');
    } catch {
      toast.error('Failed to save');
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <div className="page-inner">
        <div className="loading-skeleton" />
      </div>
    );
  }

  return (
    <div className="page-inner">
      <div className="page-header">
        <div>
          <h1 className="page-title">Availability</h1>
          <p className="page-subtitle">Set when you're available for meetings</p>
        </div>
        <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
          {saving ? <span className="spinner" /> : null}
          Save Changes
        </button>
      </div>

      <div className="avail-layout">
        <div className="avail-main card">
          <div className="avail-section-header">
            <h3>Weekly Hours</h3>
            <p>Set your regular working hours for each day of the week</p>
          </div>

          <div className="days-list">
            {DAYS.map((name, i) => (
              <div key={i} className={`day-row ${slots[i]?.enabled ? 'enabled' : ''}`}>
                <label className="day-toggle">
                  <input
                    type="checkbox"
                    checked={slots[i]?.enabled || false}
                    onChange={() => toggleDay(i)}
                    className="toggle-input"
                  />
                  <span className="toggle-track">
                    <span className="toggle-thumb" />
                  </span>
                  <span className="day-name">{name}</span>
                </label>

                {slots[i]?.enabled ? (
                  <div className="time-range">
                    <select
                      className="form-input form-select time-select"
                      value={slots[i]?.start}
                      onChange={e => updateSlot(i, 'start', e.target.value)}
                    >
                      {TIME_OPTIONS.map(t => (
                        <option key={t.value} value={t.value}>{t.label}</option>
                      ))}
                    </select>
                    <span className="time-dash">–</span>
                    <select
                      className="form-input form-select time-select"
                      value={slots[i]?.end}
                      onChange={e => updateSlot(i, 'end', e.target.value)}
                    >
                      {TIME_OPTIONS.map(t => (
                        <option key={t.value} value={t.value}>{t.label}</option>
                      ))}
                    </select>
                  </div>
                ) : (
                  <span className="unavailable-label">Unavailable</span>
                )}
              </div>
            ))}
          </div>
        </div>

        <div className="avail-sidebar">
          <div className="card" style={{ padding: 22 }}>
            <h3 style={{ fontSize: 15, fontWeight: 700, marginBottom: 6 }}>Timezone</h3>
            <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 14 }}>
              All availability times are based on this timezone
            </p>
            <select
              className="form-input form-select"
              value={timezone}
              onChange={e => setTimezone(e.target.value)}
            >
              {TIMEZONES.map(tz => (
                <option key={tz} value={tz}>{tz.replace('_', ' ')}</option>
              ))}
            </select>
          </div>

          <div className="card" style={{ padding: 22, marginTop: 16 }}>
            <h3 style={{ fontSize: 15, fontWeight: 700, marginBottom: 6 }}>Quick Setup</h3>
            <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 14 }}>
              Apply a common schedule preset
            </p>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              <button
                className="btn btn-secondary btn-sm"
                style={{ justifyContent: 'flex-start' }}
                onClick={() => {
                  const s = {};
                  for (let i = 0; i < 7; i++) {
                    s[i] = { enabled: i < 5, start: '09:00', end: '17:00' };
                  }
                  setSlots(s);
                }}
              >
                Mon–Fri, 9am–5pm
              </button>
              <button
                className="btn btn-secondary btn-sm"
                style={{ justifyContent: 'flex-start' }}
                onClick={() => {
                  const s = {};
                  for (let i = 0; i < 7; i++) {
                    s[i] = { enabled: i < 6, start: '08:00', end: '18:00' };
                  }
                  setSlots(s);
                }}
              >
                Mon–Sat, 8am–6pm
              </button>
              <button
                className="btn btn-secondary btn-sm"
                style={{ justifyContent: 'flex-start' }}
                onClick={() => {
                  const s = {};
                  for (let i = 0; i < 7; i++) {
                    s[i] = { enabled: true, start: '10:00', end: '20:00' };
                  }
                  setSlots(s);
                }}
              >
                Every day, 10am–8pm
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
